const express = require('express');
const session = require('express-session');
const axios = require('axios');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');

const app = express();

const OIDC_CONFIG = {
  issuer: process.env.OIDC_ISSUER || 'https://your-oidc-provider.com',
  clientId: process.env.OIDC_CLIENT_ID,
  clientSecret: process.env.OIDC_CLIENT_SECRET,
  redirectUri: process.env.OIDC_REDIRECT_URI || 'http://localhost:3000/callback',
  scope: 'openid profile email'
};

let discoveryDocument = null;
let jwksClientInstance = null;

async function initializeOIDC() {
  const response = await axios.get(`${OIDC_CONFIG.issuer}/.well-known/openid-configuration`);
  discoveryDocument = response.data;
  
  jwksClientInstance = jwksClient({
    jwksUri: discoveryDocument.jwks_uri,
    cache: true,
    cacheMaxAge: 86400000,
    rateLimit: true
  });
}

function getSigningKey(header, callback) {
  jwksClientInstance.getSigningKey(header.kid, (err, key) => {
    if (err) {
      return callback(err);
    }
    const signingKey = key.getPublicKey();
    callback(null, signingKey);
  });
}

function verifyIdToken(idToken, nonce) {
  return new Promise((resolve, reject) => {
    const decodedHeader = jwt.decode(idToken, { complete: true });
    
    if (!decodedHeader) {
      return reject(new Error('Invalid token format'));
    }

    getSigningKey(decodedHeader.header, (err, signingKey) => {
      if (err) {
        return reject(err);
      }

      try {
        const verified = jwt.verify(idToken, signingKey, {
          algorithms: ['RS256', 'RS384', 'RS512'],
          issuer: OIDC_CONFIG.issuer,
          audience: OIDC_CONFIG.clientId,
          clockTolerance: 60
        });

        if (nonce && verified.nonce !== nonce) {
          return reject(new Error('Nonce mismatch'));
        }

        if (verified.exp && Date.now() >= verified.exp * 1000) {
          return reject(new Error('Token expired'));
        }

        if (verified.iat && verified.iat > Date.now() / 1000 + 60) {
          return reject(new Error('Token issued in the future'));
        }

        resolve(verified);
      } catch (error) {
        reject(error);
      }
    });
  });
}

app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'lax',
    maxAge: 3600000
  }
}));

app.use(express.urlencoded({ extended: true }));
app.use(express.json());

app.get('/login', (req, res) => {
  const state = crypto.randomBytes(32).toString('hex');
  const nonce = crypto.randomBytes(32).toString('hex');
  
  req.session.state = state;
  req.session.nonce = nonce;
  
  const authUrl = new URL(discoveryDocument.authorization_endpoint);
  authUrl.searchParams.append('client_id', OIDC_CONFIG.clientId);
  authUrl.searchParams.append('redirect_uri', OIDC_CONFIG.redirectUri);
  authUrl.searchParams.append('response_type', 'code');
  authUrl.searchParams.append('scope', OIDC_CONFIG.scope);
  authUrl.searchParams.append('state', state);
  authUrl.searchParams.append('nonce', nonce);
  
  res.redirect(authUrl.toString());
});

app.get('/callback', async (req, res) => {
  try {
    const { code, state } = req.query;
    
    if (!code || !state) {
      return res.status(400).send('Missing code or state parameter');
    }
    
    if (state !== req.session.state) {
      return res.status(400).send('State mismatch - possible CSRF attack');
    }
    
    const nonce = req.session.nonce;
    delete req.session.state;
    delete req.session.nonce;
    
    const tokenResponse = await axios.post(
      discoveryDocument.token_endpoint,
      new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: OIDC_CONFIG.redirectUri,
        client_id: OIDC_CONFIG.clientId,
        client_secret: OIDC_CONFIG.clientSecret
      }),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      }
    );
    
    const { id_token, access_token, refresh_token } = tokenResponse.data;
    
    const claims = await verifyIdToken(id_token, nonce);
    
    req.session.user = {
      sub: claims.sub,
      email: claims.email,
      name: claims.name,
      picture: claims.picture,
      email_verified: claims.email_verified
    };
    
    req.session.tokens = {
      access_token: access_token,
      refresh_token: refresh_token,
      id_token: id_token
    };
    
    res.redirect('/profile');
  } catch (error) {
    console.error('Authentication error:', error.message);
    res.status(500).send('Authentication failed');
  }
});

app.get('/profile', (req, res) => {
  if (!req.session.user) {
    return res.redirect('/login');
  }
  
  res.json({
    user: req.session.user
  });
});

app.get('/logout', (req, res) => {
  req.session.destroy((err) => {
    if (err) {
      console.error('Logout error:', err);
    }
    res.redirect('/');
  });
});

app.get('/', (req, res) => {
  res.send(`
    <h1>OpenID Connect Demo</h1>
    ${req.session.user ? 
      `<p>Welcome, ${req.session.user.name}!</p><a href="/profile">Profile</a> | <a href="/logout">Logout</a>` : 
      '<a href="/login">Login</a>'}
  `);
});

async function startServer() {
  try {
    await initializeOIDC();
    const PORT = process.env.PORT || 3000;
    app.listen(PORT, () => {
      console.log(`Server running on http://localhost:${PORT}`);
    });
  } catch (error) {
    console.error('Failed to initialize OIDC:', error);
    process.exit(1);
  }
}

startServer();